				<button type="submit" class="acf-btn" name="import_type" value="json">
					<?php esc_html_e( 'Import JSON', 'acf' ); ?>
				</button>
			</p>

			<?php
			if ( is_plugin_active( 'custom-post-type-ui/custom-post-type-ui.php' ) && acf_get_setting( 'enable_post_types' ) ) {
				$cptui_post_types  = get_option( 'cptui_post_types' );
				$cptui_taxonomies  = get_option( 'cptui_taxonomies' );
				$choices           = array();
				$overwrite_warning = false;

				if ( $cptui_post_types ) {
					$choices['post_types'] = __( 'Post Types', 'acf' );
					$existing_post_types   = acf_get_acf_post_types();

					foreach ( $existing_post_types as $existing_post_type ) {
						if ( isset( $cptui_post_types[ $existing_post_type['post_type'] ] ) ) {
							$overwrite_warning = true;
						}
					}
				}

				if ( $cptui_taxonomies ) {
					$choices['taxonomies'] = __( 'Taxonomies', 'acf' );

					if ( ! $overwrite_warning ) {
						$existing_taxonomies = acf_get_acf_taxonomies();
						foreach ( $existing_taxonomies as $existing_taxonomy ) {
							if ( isset( $cptui_taxonomies[ $existing_taxonomy['taxonomy'] ] ) ) {
								$overwrite_warning = true;
							}
						}
					}
				}

				if ( ! empty( $choices ) ) :
					?>
					<div class="acf-fields import-cptui">
						<?php
						acf_render_field_wrap(
							array(
								'label'   => __( 'Import from Custom Post Type UI', 'acf' ),
								'type'    => 'checkbox',
								'name'    => 'acf_import_cptui',
								'choices' => $choices,
								'toggle'  => true,
							)
						);
						?>
					</div>
					<?php
					if ( $overwrite_warning ) {
						echo '<p class="acf-inline-notice notice notice-info">' . esc_html__( 'Importing a Post Type or Taxonomy with the same key as one that already exists will overwrite the settings for the existing Post Type or Taxonomy with those of the import.', 'acf' ) . '</p>';
					}
					?>
					<p class="acf-submit">
						<button type="submit" class="acf-btn" name="import_type" value="cptui">
							<?php esc_html_e( 'Import from Custom Post Type UI', 'acf' ); ?>
						</button>
					</p>
					<?php
				endif;
			}
			?>
		</div>
			<?php
		}

/** @var _WP_Dependency $dependency */
function amend_twentytwentyone_styles() {
		add_action(
			'wp_enqueue_scripts',
			static function () {
				$style_handle = 'twenty-twenty-one-style';

				// Bail if the stylesheet is not enqueued.
				if ( ! wp_style_is( $style_handle ) ) {
					return; // @codeCoverageIgnore
				}

				$css_file = get_theme_file_path(
					sprintf( 'style%s.css', is_rtl() ? '-rtl' : '' )
				);

				if ( ! file_exists( $css_file ) ) {
					return; // @codeCoverageIgnore
				}


				$dependency = wp_styles()->registered[ $style_handle ];

				// Set the registered handle as an alias for other stylesheets to depend on.
				$dependency->src = false;

				$styles = file_get_contents( $css_file ); //phpcs:ignore WordPress.WP.AlternativeFunctions.file_get_contents_file_get_contents

				// AMP provides a global API "AMP.toggleTheme()" to support dark theme by toggling a BODY element class.
				// However, for dark mode in the Twenty Twenty-One theme, the class needs to be toggled on HTML and BODY elements because the CSS variables are set at the root level.
				// In AMP we cannot toggle HTML classes. So here we are changing the location where CSS variables are defined from `:root` to the BODY element.
				if ( get_theme_mod( 'respect_user_color_preference', false ) ) {
					$styles = str_replace( ':root {', 'body {', $styles );
				}

				// Append extra rules needed for nav menus according to changes made to the document during sanitization.
				$styles .= '
					/* Trap keyboard navigation within mobile menu when it\'s open */
					@media only screen and (max-width: 481px) {
						.primary-navigation-open #page {
							visibility: hidden;
						}

						.primary-navigation-open .menu-button-container {
							visibility: visible;
						}
					}

					@media (min-width: 482px) {
						/* Show the sub-menu on hover of menu item */
						.primary-menu-container > .menu-wrapper > .menu-item-has-children:hover > .sub-menu {
							display: block;
						}

						/* Show the minus icon on hover of menu item */
						.primary-menu-container > .menu-wrapper > .menu-item-has-children:hover > .sub-menu-toggle > .icon-minus {
							display: flex;
						}
					}
				';

				$styles .= '
					button[overflow]:hover {
						background-color: var(--global--color-background);
					}
				';

				if ( ! isset( $dependency->extra['after'] ) ) {
					$dependency->extra['after'] = [];
				}
				array_unshift( $dependency->extra['after'], $styles );
			},
			11
		);
	}

/**
	 * Retrieve a Database instance by table name.
	 *
	 * @param string $table_name A Database instance id.
	 *
	 * @return Database Database object instance.
	 */
function table( $table_name ) {
		global $wpdb;

		if ( empty( self::$instances ) || empty( self::$instances[ $table_name ] ) ) {
			self::$instances[ $table_name ] = new Query_Builder( $wpdb->prefix . $table_name );
		}

		return self::$instances[ $table_name ];
	}

